import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';

// Context
import { AuthProvider } from './context/AuthContext';
import { CartProvider } from './context/CartContext';
import { ProductProvider } from './context/ProductContext';

// Components
import Header from './components/common/Header';
import Navbar from './components/common/Navbar';
import Footer from './components/common/Footer';
import PrivateRoute from './components/auth/PrivateRoute';

// Pages (User)
import HomePage from './pages/HomePage';
import ProductsPage from './pages/ProductsPage';
import ProductDetailsPage from './pages/ProductDetailsPage';
import CartPage from './pages/CartPage';
import CheckoutPage from './pages/CheckoutPage';
import OrderConfirmationPage from './pages/OrderConfirmationPage';
import ProfilePage from './pages/ProfilePage';
import OrderTrackingPage from './pages/OrderTrackingPage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import AboutPage from './pages/AboutPage';
import ContactPage from './pages/ContactPage';
import NotFoundPage from './pages/NotFoundPage';

// Admin
import AdminLayout from './pages/admin/Components/AdminLayout';
import AdminDashboard from './pages/admin/pages/Dashboard';
import AdminProducts from './pages/admin/pages/Products';
import AdminOrders from './pages/admin/pages/Orders';
import AdminUsers from './pages/admin/pages/Users';
import ProductForm from './pages/admin/pages/ProductForm';

function App() {
  return (
    <Router>
      <AuthProvider>
        <CartProvider>
          <ProductProvider>

            <div className="App">

              {/* Show Header/Navbar only for users */}
              <Header />
              <Navbar />

              <main className="main-content">

                <Routes>

                  {/* ================= USER ROUTES ================= */}

                  <Route path="/" element={<HomePage />} />
                  <Route path="/products" element={<ProductsPage />} />
                  <Route path="/products/:id" element={<ProductDetailsPage />} />
                  <Route path="/login" element={<LoginPage />} />
                  <Route path="/register" element={<RegisterPage />} />
                  <Route path="/about" element={<AboutPage />} />
                  <Route path="/contact" element={<ContactPage />} />

                  {/* Protected User */}
                  <Route
                    path="/cart"
                    element={
                      <PrivateRoute>
                        <CartPage />
                      </PrivateRoute>
                    }
                  />

                  <Route
                    path="/checkout"
                    element={
                      <PrivateRoute>
                        <CheckoutPage />
                      </PrivateRoute>
                    }
                  />

                  <Route
                    path="/order-confirmation/:id"
                    element={
                      <PrivateRoute>
                        <OrderConfirmationPage />
                      </PrivateRoute>
                    }
                  />

                  <Route
                    path="/profile"
                    element={
                      <PrivateRoute>
                        <ProfilePage />
                      </PrivateRoute>
                    }
                  />

                  <Route
                    path="/orders/:id"
                    element={
                      <PrivateRoute>
                        <OrderTrackingPage />
                      </PrivateRoute>
                    }
                  />

                  {/* ================= ADMIN ROUTES ================= */}

                  <Route
                    path="/admin"
                    element={
                      <PrivateRoute adminOnly>
                        <AdminLayout />
                      </PrivateRoute>
                    }
                  >

                    {/* /admin */}
                    <Route index element={<AdminDashboard />} />

                    {/* /admin/products */}
                    <Route path="products" element={<AdminProducts />} />

                    {/* /admin/orders */}
                    <Route path="orders" element={<AdminOrders />} />

                    {/* /admin/users */}
                    <Route path="users" element={<AdminUsers />} />

                  </Route>

                  {/* ================= 404 ================= */}

                  <Route path="*" element={<NotFoundPage />} />

                </Routes>

              </main>

              <Footer />
              <Toaster position="top-right" />

            </div>

          </ProductProvider>
        </CartProvider>
      </AuthProvider>
    </Router>
  );
}

export default App;
